'use client';

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { appointments as appointmentsData } from '@/lib/data';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';
import { Calendar as CalendarIcon, MapPin, AlertCircle, CheckCircle, Pencil, X, Search } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { useState } from 'react';
import { Appointment } from '@/lib/types';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '@/components/ui/dialog';
import { Label } from '@/components/ui/label';
import { Input } from '@/components/ui/input';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar } from '@/components/ui/calendar';
import { cn } from '@/lib/utils';
import Image from 'next/image';

const mapLocations = [
    { name: 'Clínica del Sol', address: 'Clínica del Sol' },
    { name: 'Laboratorio Central', address: 'Laboratorio Central' },
    { name: 'Farmacia Comunitaria', address: 'Farmacia Comunitaria' },
    { name: 'Centro de Salud', address: 'Centro de Salud Urbano' },
];

export default function AgendaPage() {
  const [appointments, setAppointments] = useState<Appointment[]>(appointmentsData);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [isMapDialogOpen, setIsMapDialogOpen] = useState(false);
  const [selectedAppointment, setSelectedAppointment] = useState<Appointment | null>(null);

  const clinicalAppointments = appointments.filter(
    (a) => a.type === 'Control trimestral' || a.type === 'Exámenes de sangre'
  );
  const deliveryVisits = appointments.filter(
    (a) => a.type === 'Solicitud de Entrega'
  );

  const handleEditClick = (appointment: Appointment) => {
    setSelectedAppointment(appointment);
    setIsEditDialogOpen(true);
  };

  const handleSaveChanges = () => {
    if (!selectedAppointment) return;

    setAppointments(prev => 
      prev.map(appt => 
        appt.id === selectedAppointment.id ? selectedAppointment : appt
      )
    );
    setIsEditDialogOpen(false);
    setSelectedAppointment(null);
  };
  
  const handleDateFieldChange = (date: Date | undefined) => {
    if (selectedAppointment && date) {
      const newDate = new Date(selectedAppointment.date);
      newDate.setFullYear(date.getFullYear(), date.getMonth(), date.getDate());
      setSelectedAppointment({ ...selectedAppointment, date: newDate });
    }
  };

  const handleTimeFieldChange = (time: string) => {
    if (selectedAppointment) {
      const [hours, minutes] = time.split(':');
      const newDate = new Date(selectedAppointment.date);
      newDate.setHours(parseInt(hours, 10), parseInt(minutes, 10));
      setSelectedAppointment({ ...selectedAppointment, date: newDate });
    }
  };

  const handleLocationSelect = (location: string) => {
    if (selectedAppointment) {
        setSelectedAppointment({ ...selectedAppointment, location });
    }
    setIsMapDialogOpen(false);
  };

  return (
    <>
      <Tabs defaultValue="clinical" className="w-full">
        <TabsList className="grid w-full grid-cols-2">
          <TabsTrigger value="clinical">Citas de Control</TabsTrigger>
          <TabsTrigger value="delivery">Entrega de Medicamento</TabsTrigger>
        </TabsList>
        <TabsContent value="clinical">
          <Card>
            <CardHeader>
              <CardTitle>Citas de Control Médico</CardTitle>
              <CardDescription>Requeridas cada 3 meses para la continuidad de PrEP.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              {clinicalAppointments.map((appt) => (
                <Card key={appt.id} className="p-4">
                  <div className="flex items-start gap-4">
                    <CalendarIcon className="mt-1 h-5 w-5 shrink-0 text-primary" />
                    <div className='flex-grow'>
                      <p className="font-semibold">{appt.type}</p>
                      <p className="text-sm capitalize">
                        {format(new Date(appt.date), "eeee, dd 'de' MMMM, yyyy 'a las' p", { locale: es })}
                      </p>
                      <div className="mt-2 flex items-center gap-2 text-sm text-muted-foreground">
                        <MapPin className="h-4 w-4" />
                        <span>{appt.location}</span>
                      </div>
                      {appt.notes && (
                        <div className="mt-3 flex items-start gap-2 rounded-md border border-yellow-200 bg-yellow-50 p-3 text-sm text-yellow-900 dark:border-yellow-800 dark:bg-yellow-950 dark:text-yellow-200">
                          <AlertCircle className="mt-0.5 h-4 w-4 shrink-0" />
                          <p><span className='font-bold'>¡Importante! </span>{appt.notes}</p>
                        </div>
                      )}
                    </div>
                    <Button variant="ghost" size="icon" onClick={() => handleEditClick(appt)}>
                      <Pencil className="h-4 w-4" />
                    </Button>
                  </div>
                </Card>
              ))}
            </CardContent>
          </Card>
        </TabsContent>
        <TabsContent value="delivery">
          <Card>
            <CardHeader>
              <CardTitle>Visitas para Radicar Solicitud</CardTitle>
              <CardDescription>Gestiona la entrega de tu medicamento.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              {deliveryVisits.map((visit) => (
                 <Card key={visit.id} className="p-4">
                  <p className="font-semibold">Próxima Visita de Radicación</p>
                  <p className='text-sm text-muted-foreground'>Tu próxima solicitud debe radicarse antes del:</p>
                  <p className="text-lg font-bold text-primary">{format(new Date(visit.date), "dd 'de' MMMM, yyyy", { locale: es })}</p>
                  <div className="mt-2 flex items-center gap-2 text-sm">
                    <MapPin className="h-4 w-4 text-muted-foreground" />
                    <span>{visit.location}</span>
                  </div>
                  <div className="mt-4 flex gap-2">
                    <Button>
                      <CheckCircle className="mr-2 h-4 w-4" /> Marcar como Radicada
                    </Button>
                    <Button variant="outline">Ver Puntos de Radicación</Button>
                  </div>
                 </Card>
              ))}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Editar Cita</DialogTitle>
            <DialogDescription>
              Modifica los detalles de tu cita y guarda los cambios.
            </DialogDescription>
          </DialogHeader>
          {selectedAppointment && (
            <div className="grid gap-4 py-4">
              <div className="grid grid-cols-4 items-center gap-4">
                <Label htmlFor="location" className="text-right">
                  Lugar
                </Label>
                <div className="col-span-3 flex gap-2">
                    <Input
                      id="location"
                      value={selectedAppointment.location}
                      onChange={(e) => setSelectedAppointment({ ...selectedAppointment, location: e.target.value })}
                      className="flex-grow"
                    />
                    <Button variant="outline" size="icon" onClick={() => setIsMapDialogOpen(true)}>
                        <Search className="h-4 w-4" />
                    </Button>
                </div>
              </div>
              <div className="grid grid-cols-4 items-center gap-4">
                <Label htmlFor="date" className="text-right">
                  Fecha
                </Label>
                <Popover>
                  <PopoverTrigger asChild>
                    <Button
                      variant={"outline"}
                      className={cn(
                        "col-span-3 justify-start text-left font-normal",
                        !selectedAppointment.date && "text-muted-foreground"
                      )}
                    >
                      <CalendarIcon className="mr-2 h-4 w-4" />
                      {selectedAppointment.date ? format(selectedAppointment.date, "PPP", { locale: es }) : <span>Elige una fecha</span>}
                    </Button>
                  </PopoverTrigger>
                  <PopoverContent className="w-auto p-0">
                    <Calendar
                      mode="single"
                      selected={new Date(selectedAppointment.date)}
                      onSelect={handleDateFieldChange}
                      initialFocus
                      locale={es}
                    />
                  </PopoverContent>
                </Popover>
              </div>
              <div className="grid grid-cols-4 items-center gap-4">
                <Label htmlFor="time" className="text-right">
                  Hora
                </Label>
                <Input
                  id="time"
                  type="time"
                  value={format(new Date(selectedAppointment.date), 'HH:mm')}
                  onChange={(e) => handleTimeFieldChange(e.target.value)}
                  className="col-span-3"
                />
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsEditDialogOpen(false)}>Cancelar</Button>
            <Button onClick={handleSaveChanges}>Guardar Cambios</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={isMapDialogOpen} onOpenChange={setIsMapDialogOpen}>
        <DialogContent className="sm:max-w-2xl">
            <DialogHeader>
                <DialogTitle>Seleccionar Ubicación</DialogTitle>
                <DialogDescription>
                    Elige una ubicación de la lista o busca en el mapa.
                </DialogDescription>
            </DialogHeader>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="md:col-span-1 space-y-2">
                    <h3 className="font-semibold">Ubicaciones Guardadas</h3>
                    {mapLocations.map(loc => (
                        <Button key={loc.name} variant="ghost" className="w-full justify-start" onClick={() => handleLocationSelect(loc.address)}>
                            {loc.name}
                        </Button>
                    ))}
                </div>
                <div className="md:col-span-2 rounded-lg overflow-hidden relative h-64 md:h-auto">
                    <Image 
                        src="https://picsum.photos/seed/map/800/600" 
                        alt="Mapa de ubicaciones" 
                        layout="fill"
                        objectFit="cover"
                        data-ai-hint="city map"
                    />
                    <p className="absolute bottom-2 left-2 bg-background/80 p-2 rounded-md text-xs">
                        Mapa de marcador de posición. Haz clic en un botón de la izquierda.
                    </p>
                </div>
            </div>
             <DialogFooter>
                <Button variant="outline" onClick={() => setIsMapDialogOpen(false)}>Cerrar</Button>
            </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}
